const PatternAsset = require('../models/PatternAsset');
const { validateRequest } = require('../middleware/validation');

class PatternController {
  // 获取图案清单
  static async getManifest(req, res) {
    try {
      const manifest = await PatternAsset.getManifest();
      
      // 设置缓存头
      res.set({
        'Cache-Control': 'public, max-age=300', // 5分钟缓存
        'ETag': `"${Date.now()}"`,
        'Last-Modified': new Date().toUTCString()
      });
      
      res.json(manifest);
    } catch (error) {
      console.error('获取图案清单失败:', error);
      res.status(500).json({
        success: false,
        message: '获取图案清单失败',
        error: error.message
      });
    }
  }

  // 获取单个图案数据
  static async getPattern(req, res) {
    try {
      const { id } = req.params;
      
      if (!id) {
        return res.status(400).json({
          success: false,
          message: '图案ID不能为空'
        });
      }

      const pattern = await PatternAsset.getById(id);
      if (!pattern) {
        return res.status(404).json({
          success: false,
          message: '图案不存在'
        });
      }

      // 设置缓存头
      res.set({
        'Cache-Control': 'public, max-age=3600', // 1小时缓存
        'ETag': `"${pattern.hash}"`,
        'Last-Modified': pattern.updated_at.toUTCString()
      });

      res.json({
        id: pattern.id,
        key: pattern.key,
        width: pattern.width,
        height: pattern.height,
        encoding: pattern.encoding,
        payload: pattern.payload,
        verified: pattern.verified
      });
    } catch (error) {
      console.error('获取图案失败:', error);
      res.status(500).json({
        success: false,
        message: '获取图案失败',
        error: error.message
      });
    }
  }

  // 创建图案（管理员功能）
  static async createPattern(req, res) {
    try {
      const { key, width, height, encoding, payload, verified = false } = req.body;
      const userId = req.user.id;

      // 验证必需字段
      if (!key || !width || !height || !encoding || !payload) {
        return res.status(400).json({
          success: false,
          message: '缺少必需字段'
        });
      }

      // 验证尺寸限制
      if (width > 32 || height > 32) {
        return res.status(400).json({
          success: false,
          message: '图案尺寸不能超过32x32'
        });
      }

      // 验证编码格式
      if (!['rle', 'png_base64'].includes(encoding)) {
        return res.status(400).json({
          success: false,
          message: '不支持的编码格式'
        });
      }

      // 检查key是否已存在
      const existingPattern = await PatternAsset.getByKey(key);
      if (existingPattern) {
        return res.status(400).json({
          success: false,
          message: '图案key已存在'
        });
      }

      // 创建图案
      const pattern = await PatternAsset.create({
        key,
        width,
        height,
        encoding,
        payload,
        verified,
        created_by: userId
      });

      res.status(201).json({
        success: true,
        message: '图案创建成功',
        pattern: {
          id: pattern.id,
          key: pattern.key,
          width: pattern.width,
          height: pattern.height,
          encoding: pattern.encoding,
          verified: pattern.verified
        }
      });
    } catch (error) {
      console.error('创建图案失败:', error);
      res.status(500).json({
        success: false,
        message: '创建图案失败',
        error: error.message
      });
    }
  }

  // 更新图案（管理员功能）
  static async updatePattern(req, res) {
    try {
      const { id } = req.params;
      const updateData = req.body;

      if (!id) {
        return res.status(400).json({
          success: false,
          message: '图案ID不能为空'
        });
      }

      const pattern = await PatternAsset.getById(id);
      if (!pattern) {
        return res.status(404).json({
          success: false,
          message: '图案不存在'
        });
      }

      // 更新图案
      await pattern.update(updateData);

      res.json({
        success: true,
        message: '图案更新成功',
        pattern: {
          id: pattern.id,
          key: pattern.key,
          width: pattern.width,
          height: pattern.height,
          encoding: pattern.encoding,
          verified: pattern.verified
        }
      });
    } catch (error) {
      console.error('更新图案失败:', error);
      res.status(500).json({
        success: false,
        message: '更新图案失败',
        error: error.message
      });
    }
  }

  // 验证图案（管理员功能）
  static async verifyPattern(req, res) {
    try {
      const { id } = req.params;

      if (!id) {
        return res.status(400).json({
          success: false,
          message: '图案ID不能为空'
        });
      }

      const pattern = await PatternAsset.getById(id);
      if (!pattern) {
        return res.status(404).json({
          success: false,
          message: '图案不存在'
        });
      }

      // 验证图案
      await pattern.verify();

      res.json({
        success: true,
        message: '图案验证成功'
      });
    } catch (error) {
      console.error('验证图案失败:', error);
      res.status(500).json({
        success: false,
        message: '验证图案失败',
        error: error.message
      });
    }
  }

  // 删除图案（软删除）
  static async deletePattern(req, res) {
    try {
      const { id } = req.params;

      if (!id) {
        return res.status(400).json({
          success: false,
          message: '图案ID不能为空'
        });
      }

      const pattern = await PatternAsset.getById(id);
      if (!pattern) {
        return res.status(404).json({
          success: false,
          message: '图案不存在'
        });
      }

      // 软删除图案
      await pattern.softDelete();

      res.json({
        success: true,
        message: '图案删除成功'
      });
    } catch (error) {
      console.error('删除图案失败:', error);
      res.status(500).json({
        success: false,
        message: '删除图案失败',
        error: error.message
      });
    }
  }

  // 获取已验证的图案列表
  static async getVerifiedPatterns(req, res) {
    try {
      const patterns = await PatternAsset.getVerifiedPatterns();
      
      const patternList = patterns.map(pattern => ({
        id: pattern.id,
        key: pattern.key,
        width: pattern.width,
        height: pattern.height,
        encoding: pattern.encoding,
        verified: pattern.verified
      }));

      res.json({
        success: true,
        patterns: patternList
      });
    } catch (error) {
      console.error('获取已验证图案失败:', error);
      res.status(500).json({
        success: false,
        message: '获取已验证图案失败',
        error: error.message
      });
    }
  }
}

module.exports = PatternController;
